blog_listing_structure.example:
{% for post in contents %}
<article>
  {% if post.featured_image %}
  <img src="{{ post.featured_image }}" alt="{{ post.featured_image_alt_text }}">
  {% endif %}
  <h2><a href="{{ post.absolute_url }}">{{ post.name }}</a></h2>
  <time>{{ post.publish_date|format_datetime('long') }}</time>
  <div>{{ post.post_list_content }}</div>
</article>
{% endfor %}

{# Pagination #}
{% if current_page_num > 1 %}
<a href="{{ blog_page_link(current_page_num - 1) }}">Previous</a>
{% endif %}
{% if current_page_num < last_page_num %}
<a href="{{ blog_page_link(current_page_num + 1) }}">Next</a>
{% endif %}
